class CustomStack:

    def __init__(self, maxSize: int):
        self.max_size = maxSize
        self.stack = []
        self.increments = [0] * maxSize

    def push(self, x: int) -> None:
        if len(self.stack) < self.max_size:
            self.stack.append(x)

    def pop(self) -> int:
        if not self.stack:
            return -1

        idx = len(self.stack) - 1

        current_inc = self.increments[idx]

        val = self.stack.pop()

        if idx > 0:
            self.increments[idx - 1] += current_inc

        self.increments[idx] = 0

        return val + current_inc

    def increment(self, k: int, val: int) -> None:
        target_idx = min(k, len(self.stack)) - 1

        if target_idx >= 0:
            self.increments[target_idx] += val
